@using sv_d19b7d779cf045ca83ceee394aa27976.Services

<div class="settings-sidebar">
    <h5 class="sidebar-title">Settings</h5>
    <nav class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <button class="sidebar-item @(section == ActiveSection ? "active" : "")"
                    @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                @section
            </button>
        }
    </nav>
</div>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = ["Profile", "Notifications", "Security", "Appearance"];

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@using sv_d19b7d779cf045ca83ceee394aa27976.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading profile…</p>
    }
    else
    {
        <div class="profile-layout">
            <div class="avatar-area">
                <img src="@_displayName" alt="Avatar" class="avatar-preview"
                     onerror="this.style.display='none'" style="display:none" />
                <div class="avatar-placeholder">
                    <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                </div>
                <div class="avatar-url text-muted small mt-1">@_avatarUrl</div>
            </div>

            <div class="profile-fields">
                <div class="field-group">
                    <label for="displayName">Display Name</label>
                    <input id="displayName" type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="field-group">
                    <label for="email">Email</label>
                    <input id="email" type="email" class="form-control" @bind="_email" />
                </div>
                <div class="field-group">
                    <label for="bio">Bio</label>
                    <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                </div>

                <div class="button-row">
                    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                        @(_saving ? "Saving…" : "Save Changes")
                    </button>
                    <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                        Discard Changes
                    </button>
                </div>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success mt-2 fade-in">@_successMessage</div>
                }
            </div>
        </div>
    }
</div>

@code {
    private UserProfile? _saved;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    protected override async Task OnInitializedAsync()
    {
        _saved = await SettingsService.GetProfileAsync();
        ApplyProfile(_saved);
        _loading = false;
    }

    private void ApplyProfile(UserProfile p)
    {
        _displayName = p.DisplayName;
        _email = p.Email;
        _bio = p.Bio;
        _avatarUrl = p.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _saved = updated;
        _saving = false;
        _successMessage = "Profile saved successfully!";
        _ = DismissMessageAsync();
    }

    private void Discard()
    {
        if (_saved is not null)
        {
            ApplyProfile(_saved);
        }
        _successMessage = null;
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_d19b7d779cf045ca83ceee394aa27976.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences…</p>
    }
    else
    {
        <div class="toggle-group">
            <label class="toggle-row">
                <span>Email Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_emailNotifications" />
            </label>
            <label class="toggle-row">
                <span>Push Notifications</span>
                <input type="checkbox" class="form-check-input" @bind="_pushNotifications" />
            </label>
            <label class="toggle-row">
                <span>Weekly Digest</span>
                <input type="checkbox" class="form-check-input" @bind="_weeklyDigest" />
            </label>
        </div>

        <h5 class="mt-4">Muted Channels</h5>
        <div class="channel-list">
            @foreach (var channel in _allChannels)
            {
                <label class="channel-row">
                    <input type="checkbox"
                           class="form-check-input"
                           checked="@_mutedChannels.Contains(channel)"
                           @onchange="e => ToggleMute(channel, (bool)e.Value!)" />
                    <span>@channel</span>
                    @if (_mutedChannels.Contains(channel))
                    {
                        <span class="badge bg-secondary ms-2">Muted</span>
                    }
                </label>
            }
        </div>

        <div class="button-row mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save Preferences")
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-2 fade-in">@_successMessage</div>
        }
    }
</div>

@code {
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly List<string> _allChannels =
        ["#general", "#random", "#off-topic", "#engineering", "#design", "#announcements"];

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = [.. prefs.MutedChannels];
        _loading = false;
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        var prefs = new NotificationPrefs(
            _emailNotifications, _pushNotifications, _weeklyDigest,
            _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _saving = false;
        _successMessage = "Notification preferences saved!";
        _ = DismissMessageAsync();
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}

@using sv_d19b7d779cf045ca83ceee394aa27976.Services

<div class="change-password-panel">
    <button class="panel-toggle" @onclick="() => _expanded = !_expanded">
        <span>🔑 Change Password</span>
        <span class="toggle-arrow">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="field-group">
                <label for="currentPwd">Current Password</label>
                <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
            </div>
            <div class="field-group">
                <label for="newPwd">New Password</label>
                <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
            </div>
            <div class="field-group">
                <label for="confirmPwd">Confirm Password</label>
                <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
            </div>

            @if (_error is not null)
            {
                <div class="alert alert-danger mt-2">@_error</div>
            }
            @if (_success is not null)
            {
                <div class="alert alert-success mt-2 fade-in">@_success</div>
            }

            <button class="btn btn-warning mt-2" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @(_saving ? "Updating…" : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _error;
    private string? _success;

    private async Task UpdatePasswordAsync()
    {
        _error = null;
        _success = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _error = "Current password is required.";
            return;
        }
        if (_newPassword.Length < 6)
        {
            _error = "New password must be at least 6 characters.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _error = "Passwords do not match.";
            return;
        }

        _saving = true;
        await OnPasswordChanged.InvokeAsync();
        _saving = false;
        _success = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
    }
}

@using sv_d19b7d779cf045ca83ceee394aa27976.Services

<div class="sessions-area">
    <h5>Active Sessions</h5>
    <table class="table table-sm">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@FormatLastActive(session.LastActive)</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-sm btn-outline-danger"
                                    @onclick="() => RequestRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="badge bg-success">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>
</div>

@if (_sessionToRevoke is not null)
{
    <RevokeSessionDialog Session="_sessionToRevoke"
                         OnConfirm="ConfirmRevokeAsync"
                         OnCancel="CancelRevoke" />
}

@code {
    [Parameter, EditorRequired] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public string CurrentSessionId { get; set; } = "sess-1";
    [Parameter] public EventCallback<string> OnRevoke { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await OnRevoke.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private static string FormatLastActive(DateTime dt)
    {
        var diff = DateTime.UtcNow - dt;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }
}

