@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings…</p>
    }
    else
    {
        <div class="appearance-options">
            <div class="field-group">
                <label><strong>Theme</strong></label>
                <div class="radio-group">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-option">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            @theme
                        </label>
                    }
                </div>
            </div>

            <div class="field-group">
                <label><strong>Font Size</strong></label>
                <div class="radio-group">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-option">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            @size
                        </label>
                    }
                </div>
            </div>

            <div class="field-group">
                <label for="language"><strong>Language</strong></label>
                <select id="language" class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <label class="toggle-row">
                <span><strong>Compact Mode</strong></span>
                <input type="checkbox" class="form-check-input" @bind="_compactMode" />
            </label>
        </div>

        <h5 class="mt-4">Live Preview</h5>
        <div class="live-preview @GetPreviewClasses()">
            <div class="preview-header">Preview Header</div>
            <div class="preview-body">
                <p>This is how your content will look with the selected settings.</p>
                <button class="preview-button">Sample Button</button>
            </div>
        </div>

        <div class="button-row mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving…" : "Save")
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success mt-2 fade-in">@_successMessage</div>
        }
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;

    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private string GetPreviewClasses()
    {
        var theme = _theme.ToLowerInvariant();
        var size = _fontSize.ToLowerInvariant();
        var compact = _compactMode ? "compact" : "";
        return $"preview-{theme} preview-{size} {compact}".Trim();
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        await SettingsService.SaveAppearanceAsync(
            new AppearanceSettings(_theme, _fontSize, _language, _compactMode));
        _saving = false;
        _successMessage = "Appearance settings saved!";
        _ = DismissMessageAsync();
    }

    private async Task DismissMessageAsync()
    {
        await Task.Delay(3000);
        _successMessage = null;
        await InvokeAsync(StateHasChanged);
    }
}
