@using sv_d19b7d779cf045ca83ceee394aa27976.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Security</h3>

    @if (_loading)
    {
        <p class="text-muted">Loading security settings…</p>
    }
    else if (_settings is not null)
    {
        <ChangePasswordPanel OnPasswordChanged="HandlePasswordChangeAsync" />

        <div class="toggle-row mt-4">
            <span>
                Two-Factor Authentication
                @if (_settings.TwoFactorEnabled)
                {
                    <span class="badge bg-success ms-2">Enabled</span>
                }
                else
                {
                    <span class="badge bg-warning ms-2">Disabled</span>
                }
            </span>
            <input type="checkbox" class="form-check-input"
                   checked="@_settings.TwoFactorEnabled" disabled />
        </div>

        @if (_settings.LastPasswordChange is not null)
        {
            <p class="text-muted small mt-2">
                Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
            </p>
        }

        <div class="mt-4">
            <ActiveSessionsTable Sessions="_settings.Sessions"
                                 OnRevoke="RevokeSessionAsync" />
        </div>
    }
</div>

@code {
    private SecuritySettings? _settings;
    private bool _loading = true;

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task HandlePasswordChangeAsync()
    {
        await SettingsService.ChangePasswordAsync("current", "new");
        _settings = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _settings = await SettingsService.GetSecuritySettingsAsync();
    }
}

