@page "/settings"
@rendermode InteractiveServer
@using sv_d19b7d779cf045ca83ceee394aa27976.Services

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection"
                     OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

/* ── Layout ── */
.settings-dashboard {
    display: flex;
    min-height: 80vh;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    overflow: hidden;
    background: #fff;
    max-width: 1100px;
    margin: 2rem auto;
    box-shadow: 0 2px 12px rgba(0,0,0,0.06);
}

/* ── Sidebar ── */
.settings-sidebar {
    width: 220px;
    min-width: 220px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    font-size: 1.1rem;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-nav {
    display: flex;
    flex-direction: column;
    padding-top: 0.5rem;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: #e9ecef;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

/* ── Content ── */
.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #212529;
}

/* ── Form fields ── */
.field-group {
    margin-bottom: 1rem;
}

.field-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #495057;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

/* ── Toggle rows ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.6rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.channel-row {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    cursor: pointer;
}

/* ── Profile ── */
.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    text-align: center;
    flex-shrink: 0;
}

.avatar-img {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url {
    max-width: 120px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.profile-fields {
    flex: 1;
}

/* ── Change password panel ── */
.change-password-panel {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
}

.panel-toggle {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 0.75rem 1rem;
    border: none;
    background: #f8f9fa;
    font-size: 0.95rem;
    font-weight: 500;
    cursor: pointer;
    color: #495057;
}

.panel-toggle:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1rem;
    border-top: 1px solid #dee2e6;
}

/* ── Modal ── */
.modal-backdrop {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1050;
}

.modal-dialog {
    width: 100%;
    max-width: 440px;
}

.modal-content {
    background: #fff;
    border-radius: 8px;
    overflow: hidden;
    box-shadow: 0 4px 24px rgba(0,0,0,0.15);
}

.modal-header {
    padding: 1rem 1.25rem;
    border-bottom: 1px solid #dee2e6;
}

.modal-body {
    padding: 1.25rem;
}

.modal-footer {
    display: flex;
    justify-content: flex-end;
    gap: 0.5rem;
    padding: 0.75rem 1.25rem;
    border-top: 1px solid #dee2e6;
}

/* ── Appearance ── */
.radio-group {
    display: flex;
    gap: 1.25rem;
    margin-top: 0.25rem;
}

.radio-option {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    cursor: pointer;
    font-size: 0.95rem;
}

.appearance-options {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

/* ── Live preview ── */
.live-preview {
    border: 1px solid #dee2e6;
    border-radius: 6px;
    overflow: hidden;
    transition: all 0.2s;
}

.preview-header {
    padding: 0.75rem 1rem;
    font-weight: 600;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    padding: 1rem;
}

.preview-button {
    padding: 0.4rem 1rem;
    border-radius: 4px;
    border: 1px solid #0d6efd;
    background: #0d6efd;
    color: #fff;
    cursor: pointer;
}

/* Theme variants */
.preview-light {
    background: #fff;
    color: #212529;
}

.preview-light .preview-header {
    background: #f8f9fa;
}

.preview-dark {
    background: #1e1e2e;
    color: #cdd6f4;
    border-color: #45475a;
}

.preview-dark .preview-header {
    background: #181825;
    border-color: #45475a;
}

.preview-dark .preview-button {
    background: #89b4fa;
    border-color: #89b4fa;
    color: #1e1e2e;
}

.preview-system {
    background: linear-gradient(135deg, #fff 50%, #1e1e2e 50%);
    color: #495057;
}

.preview-system .preview-header {
    background: #e9ecef;
}

/* Font size variants */
.preview-small { font-size: 0.8rem; }
.preview-medium { font-size: 1rem; }
.preview-large { font-size: 1.2rem; }

/* Compact mode */
.live-preview.compact .preview-header { padding: 0.35rem 0.75rem; }
.live-preview.compact .preview-body { padding: 0.5rem 0.75rem; }
.live-preview.compact .preview-body p { margin-bottom: 0.25rem; }

/* ── Sessions table ── */
.sessions-area .table {
    margin-top: 0.5rem;
}

/* ── Toast animation ── */
.fade-in {
    animation: fadeIn 0.3s ease-in;
}

@keyframes fadeIn {
    from { opacity: 0; transform: translateY(-4px); }
    to { opacity: 1; transform: translateY(0); }
}

