    padding: 0 1.25rem 1rem;
    margin: 0;
    font-weight: 600;
    font-size: 1.1rem;
    color: #495057;
    border-bottom: 1px solid #dee2e6;
}

.sidebar-nav {
    display: flex;
    flex-direction: column;
    padding-top: 0.5rem;
}

.sidebar-item {
    display: flex;
    align-items: center;
    gap: 0.6rem;
    padding: 0.7rem 1.25rem;
    border: none;
    background: none;
    text-align: left;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: background-color 0.15s, color 0.15s;
}

.sidebar-item:hover {
    background: #e9ecef;
}

.sidebar-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 500;
}

.sidebar-icon {
    font-size: 1.1rem;
}

