.settings-content {
    flex: 1;
    padding: 2rem;
    overflow-y: auto;
}

.settings-section h3 {
    margin-top: 0;
    margin-bottom: 1.5rem;
    font-weight: 600;
    color: #212529;
}

/* ── Form fields ── */
.field-group {
    margin-bottom: 1rem;
}

.field-group label {
    display: block;
    margin-bottom: 0.3rem;
    font-weight: 500;
    font-size: 0.9rem;
    color: #495057;
}

.button-row {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
}

/* ── Toggle rows ── */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.toggle-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.6rem 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
}

/* ── Channel list ── */
.channel-list {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
}

.channel-row {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    cursor: pointer;
}

/* ── Profile ── */
.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    text-align: center;
    flex-shrink: 0;
}

.avatar-img {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
}

.avatar-url {
    max-width: 120px;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.profile-fields {
    flex: 1;
}

