+    align-items: center;
+    width: 100%;
+    padding: 0.75rem 1rem;
+    border: none;
+    background: #f8f9fa;
+    font-size: 0.95rem;
+    font-weight: 500;
+    cursor: pointer;
+    color: #495057;
+}
+
+.panel-toggle:hover {
+    background: #e9ecef;
+}
+
+.panel-body {
+    padding: 1rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* ── Modal ── */
+.modal-backdrop {
+    position: fixed;
+    inset: 0;
+    background: rgba(0,0,0,0.5);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1050;
+}
+
+.modal-dialog {
+    width: 100%;
+    max-width: 440px;
+}
+
+.modal-content {
+    background: #fff;
+    border-radius: 8px;
+    overflow: hidden;
+    box-shadow: 0 4px 24px rgba(0,0,0,0.15);
+}
+
+.modal-header {
+    padding: 1rem 1.25rem;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.modal-body {
+    padding: 1.25rem;
+}
+
+.modal-footer {
+    display: flex;
+    justify-content: flex-end;
+    gap: 0.5rem;
+    padding: 0.75rem 1.25rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* ── Appearance ── */
+.radio-group {
+    display: flex;
+    gap: 1.25rem;
+    margin-top: 0.25rem;
+}
+
+.radio-option {
+    display: flex;
+    align-items: center;
+    gap: 0.35rem;
+    cursor: pointer;
+    font-size: 0.95rem;
+}
+
+.appearance-options {
+    display: flex;
+    flex-direction: column;
+    gap: 0.5rem;
+}
+
+/* ── Live preview ── */
+.live-preview {
+    border: 1px solid #dee2e6;
+    border-radius: 6px;
+    overflow: hidden;
+    transition: all 0.2s;
+}
+
+.preview-header {
+    padding: 0.75rem 1rem;
+    font-weight: 600;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.preview-body {
+    padding: 1rem;
+}
+
+.preview-button {
+    padding: 0.4rem 1rem;
+    border-radius: 4px;
+    border: 1px solid #0d6efd;
+    background: #0d6efd;
+    color: #fff;
+    cursor: pointer;
+}
+
+/* Theme variants */
+.preview-light {
+    background: #fff;
+    color: #212529;
+}
+
+.preview-light .preview-header {
+    background: #f8f9fa;
+}
+
+.preview-dark {
+    background: #1e1e2e;
+    color: #cdd6f4;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-header {
+    background: #181825;
+    border-color: #45475a;
+}
+
+.preview-dark .preview-button {
+    background: #89b4fa;
+    border-color: #89b4fa;
+    color: #1e1e2e;
+}
+
+.preview-system {
+    background: linear-gradient(135deg, #fff 50%, #1e1e2e 50%);
+    color: #495057;
+}
+
+.preview-system .preview-header {
+    background: #e9ecef;
+}
+
+/* Font size variants */
+.preview-small { font-size: 0.8rem; }
+.preview-medium { font-size: 1rem; }
+.preview-large { font-size: 1.2rem; }
+
+/* Compact mode */
+.live-preview.compact .preview-header { padding: 0.35rem 0.75rem; }
+.live-preview.compact .preview-body { padding: 0.5rem 0.75rem; }
+.live-preview.compact .preview-body p { margin-bottom: 0.25rem; }
+
+/* ── Sessions table ── */
+.sessions-area .table {
+    margin-top: 0.5rem;
+}
+
+/* ── Toast animation ── */
+.fade-in {
+    animation: fadeIn 0.3s ease-in;
+}
+
+@keyframes fadeIn {
+    from { opacity: 0; transform: translateY(-4px); }
+    to { opacity: 1; transform: translateY(0); }
+}
